      align-items: baseline;    /* 保证标签和文本底边对齐 */
      gap: 0;
      transition: border-color 0.2s, background 0.2s;
      word-break: break-word;   /* 长单词或链接可断 */
    }

    .ssc-row:hover {
      border-color: rgba(255, 255, 255, 0.28);
      background: rgba(255, 255, 255, 0.04);
    }

    /* 左侧标签（如“时间”“地点”） */
    .ssc-label {
      color: rgba(255, 255, 255, 0.6);
      font-weight: 400;
      white-space: nowrap;      /* 标签不换行，避免冒号错位 */
      flex-shrink: 0;
      max-width: 40%;           /* 极端情况下防止过长标签挤压右侧 */
    }

    /* 冒号分隔符 */
    .ssc-colon {
      color: rgba(255, 255, 255, 0.3);
      padding: 0 6px;
      flex-shrink: 0;
    }

    /* 右侧具体文本 – 灵活换行 */
    .ssc-text {
      color: rgba(255, 255, 255, 0.88);
      font-weight: 400;
      flex: 1;
      word-break: break-word;
      line-height: 1.6;         /* 略小于父级，提升多行阅读舒适度 */
    }

    /* ---------- 移动端适配 (屏幕宽度小于 600px) ---------- */
    @media (max-width: 600px) {
      body {
        padding: 6px 10px;      /* 略微减少左右留白，给内容更多空间 */
      }

      .ssc-title {
        font-size: 1.15rem;      /* 约18.4px，适中 */
        letter-spacing: 0.2em;   /* 字间距稍减，避免拥挤 */
      }

      .ssc-summary {
        gap: 8px;                /* 元素间距缩小 */
        padding: 12px 0;         /* 点击区域稍微缩小但依然够用 */
      }

      .ssc-line {
        width: 30px;             /* 装饰线缩短，适应窄屏 */
      }

      .ssc-body {
        padding: 12px 12px;      /* 卡片内边距减小，释放更多宽度 */
        border-radius: 14px;     /* 圆角略微调小更精致 */
      }

      .ssc-row {
        padding: 10px 14px;      /* 行内左右留白减少，内容更舒展 */
        font-size: 16px;         /* 正文适当减小，符合移动端阅读习惯 */
        line-height: 1.6;        /* 行高略微降低 */
      }

      .ssc-label {
        font-size: 15px;         /* 标签略小于正文但保持协调 */
      }

      .ssc-colon {
        padding: 0 4px;          /* 冒号左右间距减一点 */
      }

      .ssc-text {
        font-size: 16px;         /* 与父级一致 */
        line-height: 1.55;       /* 更紧凑 */
      }
    }

    /* 对于更小的屏幕 (≤ 380px) 做进一步微调 */
    @media (max-width: 380px) {
      .ssc-row {
        padding: 8px 12px;
        font-size: 15px;
      }
      .ssc-label {
        font-size: 14px;
      }
      .ssc-title {
        font-size: 1rem;         /* 16px */
        letter-spacing: 0.15em;
      }
      .ssc-line {
        width: 24px;
      }
      .ssc-summary {
        gap: 6px;
      }
    }

    /* 可选：确保超长标签依然可读（比如用省略号？但我们希望尽量完整显示） */
    /* 若标签实在太长，可考虑允许换行，但极少数情况，暂不处理 */
  </style>
</head>
<body>

  <!-- 原始数据容器（服务端替换$1为实际内容） -->
  <div id="rawData" style="display:none;">$1</div>

  <details class="ssc-details">
    <summary class="ssc-summary">
      <span class="ssc-line"></span>
      <span class="ssc-title">性爱场景特写</span>
      <span class="ssc-line"></span>
    </summary>
    <div class="ssc-body" id="sscBody"></div>
  </details>

  <script>
    document.addEventListener('DOMContentLoaded', function() {
      var rawEl = document.getElementById('rawData');
      var body = document.getElementById('sscBody');

      // 获取原始文本内容（兼容多种取值方式）
      var raw = (rawEl.innerText || rawEl.textContent || '').trim();
      if (!raw) {
        // 如果innerText无效，尝试innerHTML并去除标签（防止意外HTML）
        raw = rawEl.innerHTML.replace(/<[^>]+>/g, '').trim();
      }

      // 按行分割，过滤空行
      var lines = raw.split('\n')
                     .map(function(l) { return l.trim(); })
                     .filter(function(l) { return l.length > 0; });

      // 如果没有内容，显示占位符
      if (lines.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'ssc-row';
        emptyDiv.innerHTML = '<span class="ssc-text">（暂无内容）</span>';
        body.appendChild(emptyDiv);
        return;
      }

      // 遍历每一行，尝试解析“标签：内容”格式，否则整行作为文本
      lines.forEach(function(line) {
        var div = document.createElement('div');
        div.className = 'ssc-row';

        // 匹配中英文冒号，分组捕获：标签、冒号、内容
        var match = line.match(/^([^：:]+)([：:])(.*)$/);
        if (match) {
          // 转义可能存在的HTML字符（但为保持简洁，不做双重转义，相信内容安全）
          div.innerHTML = '<span class="ssc-label">' + match[1] + '</span>' +
                          '<span class="ssc-colon">' + match[2] + '</span>' +
                          '<span class="ssc-text">' + match[3] + '</span>';
        } else {
          // 无冒号，整行作为普通文本
          div.innerHTML = '<span class="ssc-text">' + line + '</span>';
        }
        body.appendChild(div);
      });
    });
  </script>
</body>
</html>
