  // silent=true 时不弹 toastr，返回 bool 表示是否成功
  function doFmtSync(silent) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { if (!silent) toastr.warning('请先打开预设管理面板'); return false; }

    const ctx = SillyTavern.getContext();
    const fails = [];

    // 1. 探测局部正则脚本
    let regexLines = [];
    try {
      const scopedScripts = (ctx.characters?.[ctx.characterId]?.data?.extensions?.regex_scripts || []).filter(s => !s.disabled);
      regexLines = [...new Set(scopedScripts.map(s => s.findRegex).filter(Boolean))];
    } catch (_) {
      fails.push('正则脚本读取');
    }

    // 2. 探测能否写入额外格式条目
    let writeTarget = null;
    try {
      const prompts = ctx.chatCompletionSettings?.prompts || [];
      writeTarget = prompts.find(p => p.name.includes('额外格式'));
      if (!writeTarget || typeof writeTarget.content !== 'string') {
        fails.push('额外格式条目写入');
        writeTarget = null;
      }
    } catch (_) {
      fails.push('额外格式条目写入');
    }

    // 3. 探测 MVU 更新方式
    let mvuMode = null;
    try {
      mvuMode = ctx.extensionSettings?.mvu_settings?.['更新方式'];
      if (!mvuMode) fails.push('MVU变量更新方式读取');
    } catch (_) {
      fails.push('MVU变量更新方式读取');
    }

    // 任一探测失败则阻断
    if (fails.length) {
      if (!silent) toastr.error(`您的酒馆无法适配本稳定器，请到我的dc帖子咨询。\n失败项：${fails.join('、')}`, '', { timeOut: 8000 });
      return false;
    }

    // 4. 额外模型解析时过滤含 UpdateVariable 的正则
    if (mvuMode === '额外模型解析') {
      regexLines = regexLines.filter(r => !r.includes('UpdateVariable'));
    }

    // 5. 切换条目开关
    ensureOffContains('格式检查');
    ensureOnContains('格式稳定器');
    ensureOnContains('额外格式');

    // 6. 写入正则到额外格式并保存
    writeTarget.content = regexLines.join('\n');
    ctx.saveSettingsDebounced();

    fmtActive = true;
    fmtOn.classList.add('is-on');
    fmtOff.classList.remove('is-on');
    return true;
  }

