  // ── 附加参数 ──────────────────────────────────────────────
  const addParamValues = [
    'reasoning_effort: none',
    'thinking: disabled',
    '{"providerOptions": {"gateway": {"only": ["deepseek"]}, "deepseek": {"thinking": {"type": "disabled"}}}}',
    '{"thinking":{"type":"disabled"}}',
    'chat_template_kwargs:\n  thinking: true\n  reasoning_effort: max',
