  const addParamLabels = ['桃桃站', '方法1', '方法3', '方法4', '桃站DS加思维', '官DS加思维'];
  const addParamEls = [0,1,2,3].map(i => pdoc.getElementById(`${ID}-addparam-${i}`));
  const thinkParamEls = [0,1].map(i => pdoc.getElementById(`${ID}-addparam-think-${i}`));
  const allParamEls = [...addParamEls, ...thinkParamEls];
  let addParamActive = -1;

  function syncAddParamState() {
    const ctx = SillyTavern.getContext();
