  // ── 状态检测与同步 ────────────────────────────────────────
  function isKeywordOn(keyword) {
    const items = findByKeyword(keyword);
    return items.length > 0 && items.every(li => isPromptEnabled(li));
  }
  function detectLevel(levels) {
    for (let i = 0; i < levels.length; i++) {
      const { turnOn, turnOff } = levels[i];
      if (turnOn.every(kw => isKeywordOn(kw)) && turnOff.every(kw => !isKeywordOn(kw))) return i;
    }
    return -1;
  }
  function syncAllToggleBtns() {
    sexyLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === sexyActive));
    talkLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === talkActive));
    povLevels.forEach(({ el }, i)   => el.classList.toggle('is-on', i === povActive));
    povNovelEl.classList.toggle('is-on', povNovelActive);
    paraEls.forEach((el, i)  => el.classList.toggle('is-on', i === paraActive));
    paceLevels.forEach(({ el }, i)  => el.classList.toggle('is-on', i === paceActive));
    wordSegs.forEach(({ el }, i)    => el.classList.toggle('is-on', i === wordActive));
    robTalkSegs.forEach(({ el }, i) => el.classList.toggle('is-on', i === robTalkActive));
    syncAddParamState();
  }
  function initDetectState() {
    if (!pdoc.querySelector('#completion_prompt_manager_list')) return;
    sexyActive = detectLevel(sexyLevels);
    talkActive = detectLevel(talkLevels);
    povActive  = detectLevel(povLevels);
    povNovelActive = findByContains('小说创作视角').some(li => isPromptEnabled(li));
    povNovelEl.classList.toggle('is-on', povNovelActive);
    paraActive = (function() {
      const expandOn = findByContainsAll(['转述','扩写']).some(li => isPromptEnabled(li));
      if (expandOn) return 0;
      const paraOn = findByContains('转述').filter(li => {
        const n = ((li.querySelector('[data-pm-name]')||{}).getAttribute?.('data-pm-name')??'').toLowerCase();
        return !n.includes('扩写') && !n.includes('不转述');
      }).some(li => isPromptEnabled(li));
      if (paraOn) return 1;
      const noParaOn = findByContains('不转述').some(li => isPromptEnabled(li));
      if (noParaOn) return 2;
      return -1;
    })();
    paceActive = (function() {
      for (let i = 0; i < paceLevels.length; i++) {
        const li = findByExactName(paceLevels[i].name);
        if (li && isPromptEnabled(li)) return i;
      }
      return -1;
    })();
    summaryActive = isKeywordOn('大总结之术');
    itemSummary.classList.toggle('is-on', summaryActive);
    tortureActive = findByContains('拷打AI').some(li => isPromptEnabled(li));
    itemTorture.classList.toggle('is-on', tortureActive);
    mimiActive = findByContains('咪咪吐槽').some(li => isPromptEnabled(li));
    itemMimi.classList.toggle('is-on', mimiActive);
    featItems.forEach(({ id, keyword, useContains }) => {
      const el = pdoc.getElementById(id);
      if (!el) return;
      const shouldUseContains = useContains || keyword === '变量卡开关';
      const isOn = shouldUseContains
        ? findByContains(keyword).some(li => isPromptEnabled(li))
        : isKeywordOn(keyword);
      el.classList.toggle('is-on', isOn);
    });
    fanItems.forEach(({ id, keyword, useContains })  => {
      const el = pdoc.getElementById(id);
      if (!el) return;
      const isOn = useContains
        ? findByContains(keyword).some(li => isPromptEnabled(li))
        : isKeywordOn(keyword);
      el.classList.toggle('is-on', isOn);
    });
    // 字数按钮同步
    wordActive = wordSegs.findIndex(({ keyword }) => isKeywordOn(keyword));
    syncWordBtns();
    // 可抢话同步
    robTalkActive = robTalkSegs.findIndex(({ keyword }) => findByContains(keyword).some(li => isPromptEnabled(li)));
    robTalkSegs.forEach(({ el }, i) => el.classList.toggle('is-on', i === robTalkActive));
    // 格式稳定器同步
    const fmtStabOn = findByContains('格式稳定器').some(li => isPromptEnabled(li));
    fmtActive = fmtStabOn;
    fmtOn.classList.toggle('is-on', fmtActive);
    fmtOff.classList.toggle('is-on', !fmtActive);
    // 底部选择同步
    if (findByContains('ds专用--底部').some(li => isPromptEnabled(li))) bottomActive = 0;
    else if (findByContains('桃站4p专用--底部').some(li => isPromptEnabled(li))) bottomActive = 1;
    else bottomActive = -1;
    syncBottomBtns();
    // 预设核心变换检测
    const cotOn = findByContains('COT-头').some(li => isPromptEnabled(li))
               && findByContains('基础思维').some(li => isPromptEnabled(li));
    const rawOn = findByContains('原思维').some(li => isPromptEnabled(li))
               && findByContains('cot-end').some(li => isPromptEnabled(li));
    const dsRawMark = findByContains('ds原-思-维').some(li => isPromptEnabled(li));
    if (cotOn) {
      coreActive = 0;
      fmtLocked = false;
      bottomLocked = false;
    } else if (rawOn) {
      if (dsRawMark) {
        coreActive = 1; // DS原思维
      } else {
        const curTopP = SillyTavern.getContext().chatCompletionSettings.top_p_openai;
        coreActive = (Math.abs(curTopP - 0.55) < 0.01) ? 3 : 2; // KIMI or GLM
      }
      fmtLocked = true;
      bottomLocked = true;
    } else {
      coreActive = -1;
      fmtLocked = false;
      bottomLocked = false;
    }
    coreEls.forEach((el, i) => el.classList.toggle('is-on', i === coreActive));
    syncAllToggleBtns();
  }
  let initDone = false;
  function tryInitDetect() {
    if (initDone || !pdoc.querySelector('#completion_prompt_manager_list')) return;
    initDone = true;
    initDetectState();
  }
  setTimeout(tryInitDetect, 1200);
  setTimeout(tryInitDetect, 2000);

  // ── 展开/收起方向 ─────────────────────────────────────────
  function updateMenuDirection() {
    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const alignLeft = orbX < pwin.innerWidth / 2;
    menu.style.left  = alignLeft ? '0' : 'auto';
    menu.style.right = alignLeft ? 'auto' : '0';
    const goUp = orbY > pwin.innerHeight / 2;
    if (goUp) {
      menu.style.top = 'auto';
      menu.style.bottom = '58px';
      root.classList.add('open-up');
      menu.style.transformOrigin = alignLeft ? 'bottom left' : 'bottom right';
    } else {
      menu.style.top = '58px';
      menu.style.bottom = 'auto';
      root.classList.remove('open-up');
      menu.style.transformOrigin = alignLeft ? 'top left' : 'top right';
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) { updateMenuDirection(); initDetectState(); }
    else { root.classList.remove('open-up'); }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }
  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  // ── 保存位置 ──────────────────────────────────────────────
  function savePos() {
    try {
      insertOrAssignVariables({
        orbV2_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top) })
      }, { type: 'global' });
    } catch (_) {}
  }

  // ═══════════════════════════════════════════════════════
  //  拖拽系统（全平台统一重写）
  //
  //  核心改动：
  //  1. 用 pointerevent 统一 PC/移动端，不再分 mouse/touch 两套
  //  2. iOS Chrome 上 getBoundingClientRect() 时机问题：改为记录
  //     pointerdown 时的坐标与根节点当前位置做差值，不依赖 rect
  //  3. 移除 parent.document 上的鼠标事件监听（iOS WKWebView 跨域）
  //  4. pointer capture：setPointerCapture 让手指/鼠标移出元素也能跟踪
  //  5. 用 pointermove 的 movementX/Y 累加方式做备选（Safari 不支持
  //     movementX，所以仍用坐标差值方式，更稳）
  // ═══════════════════════════════════════════════════════

  let drag      = false;
  let moved     = false;
  let dragStartX = 0;   // pointerdown 时 clientX
  let dragStartY = 0;   // pointerdown 时 clientY
  let rootStartX = 0;   // pointerdown 时 root 的 left
  let rootStartY = 0;   // pointerdown 时 root 的 top
  const DRAG_THRESHOLD = 4; // px，超过才算拖拽（区分点击）

  // 仅 orb 是点击展开的起点；head 只拖拽，不 toggle
  function onOrbDragStart(e) {
    drag       = true;
    moved      = false;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    rootStartX = parseInt(root.style.left) || 0;
    rootStartY = parseInt(root.style.top)  || 0;
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
  }

  function onHeadDragStart(e) {
    if (e.target.id === `${ID}-close`) return;
    // 阻止冒泡，防止 orb 的 pointerdown 也收到
    e.stopPropagation();
    drag       = true;
    moved      = false;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    rootStartX = parseInt(root.style.left) || 0;
    rootStartY = parseInt(root.style.top)  || 0;
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
  }

  function onDragMove(e) {
    if (!drag) return;
    const dx = e.clientX - dragStartX;
    const dy = e.clientY - dragStartY;
    if (!moved && Math.abs(dx) < DRAG_THRESHOLD && Math.abs(dy) < DRAG_THRESHOLD) return;
    moved = true;
    e.preventDefault();
    const nx = Math.max(4, Math.min(rootStartX + dx, pwin.innerWidth  - 56));
    const ny = Math.max(4, Math.min(rootStartY + dy, pwin.innerHeight - 56));
    root.style.left = nx + 'px';
    root.style.top  = ny + 'px';
  }

  function onOrbDragEnd(e) {
    if (!drag) return;
    drag = false;
    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch (_) {}
    if (moved) {
      savePos();
    } else {
      toggle(); // orb 点击才 toggle
    }
  }

  function onHeadDragEnd(e) {
    if (!drag) return;
    drag = false;
    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch (_) {}
    if (moved) savePos();
    // head 点击不触发 toggle
  }

  // ── orb 绑定 ─────────────────────────────────────────────
  orb.addEventListener('pointerdown', onOrbDragStart);
  orb.addEventListener('pointermove', onDragMove, { passive: false });
  orb.addEventListener('pointerup',   onOrbDragEnd);
  orb.addEventListener('pointercancel', e => { drag = false; try { e.currentTarget.releasePointerCapture(e.pointerId); } catch(_){} });

  // ── head 绑定 ─────────────────────────────────────────────
  head.addEventListener('pointerdown', onHeadDragStart);
  head.addEventListener('pointermove', onDragMove, { passive: false });
  head.addEventListener('pointerup',   onHeadDragEnd);
  head.addEventListener('pointercancel', e => { drag = false; try { e.currentTarget.releasePointerCapture(e.pointerId); } catch(_){} });

  // ── 角色卡切换监听 ────────────────────────────────────────
  {
    const stCtx = SillyTavern.getContext();
    const { eventSource: es, eventTypes: et } = stCtx;

    // 自定义 toast（右上角淡入淡出）
    const wxToast = (msg, duration = 3500) => {
      const el = pdoc.createElement('div');
      Object.assign(el.style, {
        position: 'fixed', top: '16px', right: '16px', zIndex: '2147483647',
        padding: '12px 20px', borderRadius: '10px',
        background: 'linear-gradient(135deg, rgba(6,14,38,0.95), rgba(15,30,60,0.95))',
        border: '1px solid rgba(70,140,255,0.45)',
        boxShadow: '0 0 20px rgba(50,130,255,0.4), 0 4px 16px rgba(0,0,0,0.5)',
        color: 'rgba(200,225,255,0.95)', fontSize: '14px',
        fontFamily: "'Microsoft YaHei','PingFang SC',sans-serif",
        letterSpacing: '0.04em', pointerEvents: 'none',
        opacity: '0', transform: 'translateY(-12px)',
        transition: 'opacity 0.35s ease, transform 0.35s ease',
      });
      el.textContent = msg;
      pdoc.body.appendChild(el);
      requestAnimationFrame(() => { el.style.opacity = '1'; el.style.transform = 'translateY(0)'; });
      setTimeout(() => {
        el.style.opacity = '0'; el.style.transform = 'translateY(-12px)';
        setTimeout(() => el.remove(), 400);
      }, duration);
    };

    // mvu按钮智能切换：检测mvu状态并控制feat-2/feat-3
    async function syncMvuLock() {
      const feat2El = pdoc.getElementById(`${ID}-feat-2`);
      const feat3El = pdoc.getElementById(`${ID}-feat-3`);

      // 1. 通过世界书条目检测是否为mvu卡（带重试，防止时间竞争）
      let hasMvuEntries = false;
      const TH = pwin.TavernHelper || window.TavernHelper;
      if (TH && TH.getCurrentCharPrimaryLorebook && TH.getLorebookEntries) {
        for (let attempt = 0; attempt < 4; attempt++) {
          if (attempt > 0) await new Promise(r => setTimeout(r, 500));
          try {
            const bookName = await TH.getCurrentCharPrimaryLorebook();
            if (bookName) {
              const entries = await TH.getLorebookEntries(bookName);
              hasMvuEntries = entries?.some(e => (e.comment || '').toLowerCase().includes('mvu')) || false;
            }
          } catch (_) {}
          if (hasMvuEntries) break;
        }
      }

      // 2. 如果是mvu卡，再检查更新方式
      let mvuMode = null;
      if (hasMvuEntries) {
        try {
          const ctx = SillyTavern.getContext();
          mvuMode = ctx.extensionSettings?.mvu_settings?.['更新方式'];
        } catch (_) {}
      }

      if (!hasMvuEntries || mvuMode === '额外模型解析') {
        // 非mvu卡 或 额外模型解析模式 → 锁定并关闭
        mvuLocked = true;
        mvuLockReason = hasMvuEntries ? 'extra-model' : 'no-mvu';
        if (feat3El && feat3El.classList.contains('is-on')) {
          ensureOffContains('变量卡开关');
          feat3El.classList.remove('is-on');
        }
        if (feat2El && feat2El.classList.contains('is-on')) {
          ensureOffContains('防变量出错');
          feat2El.classList.remove('is-on');
        }
        wxToast(hasMvuEntries ? 'mvu是额外ai解析，已智能适配按钮' : '这不是mvu卡，已智能关闭相关按钮');
      } else {
        // 是mvu卡且随AI输出 → 解锁，自动开启mvu卡开我
        mvuLocked = false;
        if (feat3El && !feat3El.classList.contains('is-on')) {
          ensureOnContains('变量卡开关');
          feat3El.classList.add('is-on');
        }
      }
    }

    if (es && et) {
      es.on(et.CHAT_CHANGED, () => {
        const c = SillyTavern.getContext();
        if (!c.characterId && !c.groupId) return; // 退出角色卡不提示

        const name = c.name2 || '未知';
        if (fmtActive) {
          // 轮询等面板就绪 + 新角色数据就绪后再同步
          const targetId = c.characterId;
          let tries = 0;
          const poll = setInterval(() => {
            tries++;
            const cur = SillyTavern.getContext();
            const hasPanel = !!pdoc.querySelector('#completion_prompt_manager_list');
            const hasCharData = cur.characterId === targetId
              && cur.characters?.[targetId]?.data?.extensions != null;
            if (hasPanel && hasCharData) {
              clearInterval(poll);
              doFmtSync(true);
              syncMvuLock();
              wxToast(`已进入${name}，格式稳定器已同步`);
            } else if (tries >= 25) { // 200ms * 25 = 5秒超时
              clearInterval(poll);
              wxToast(`已进入${name}，格式稳定器同步失败`);
            }
          }, 200);
        } else {
          // 格式稳定器未开启时也检测mvu状态
          syncMvuLock();
          wxToast(`已进入${name}`);
        }
      });
    }
  }

  // ── 自动清理 ──────────────────────────────────────────────
  function cleanup() {
    try { pdoc.getElementById(ID)?.remove(); } catch(_) {}
    try { pdoc.getElementById(`${ID}-style`)?.remove(); } catch(_) {}
  }
  window.addEventListener('pagehide', cleanup);
  window.addEventListener('unload',   cleanup);

}));

$(errorCatched(async () => {
  const VERSION = 'V3.1.1';
  const sleep = ms => new Promise(resolve => setTimeout(resolve, ms));
  function getName(script) {
    return String(script?.script_name ?? script?.scriptName ?? script?.name ?? '');
  }

  function readPresetRegexesFromDom() {
    let pdoc;
    try {
      pdoc = parent?.document ?? document;
    } catch {
      pdoc = document;
    }

    return Array.from(
      pdoc.querySelectorAll('#saved_preset_scripts .regex_script_name')
    ).map(el => ({ script_name: el.textContent ?? '' }));
  }

  function readPresetRegexes() {
    if (typeof getTavernRegexes === 'function') {
      return getTavernRegexes({ type: 'preset', name: 'in_use' }) ?? [];
    }

    if (typeof getPreset === 'function') {
      return getPreset('in_use')?.extensions?.regex_scripts ?? [];
    }

    return readPresetRegexesFromDom();
  }

  let scripts = [];
  for (let i = 0; i < 10; i++) {
    scripts = readPresetRegexes();
    if (scripts.length > 0) break;
    await sleep(300);
  }

  const found = scripts.some(script => getName(script).includes(VERSION));

  if (found) {
    toastr.success('感谢使用，正则版本正确。', '', { timeOut: 5000 });
  } else {
    toastr.error(
      '您的正则未正确更新！请重新导入预设，或去我的dc帖子寻找正确正则导入。',
      '',
      { timeOut: 10000 }
    );
  }
}));
